insert into bank_questions (question_key, page_id, page_name, source, qtype, marks, snapshot, answer_key)
values
('4-2-quality-of-goods-services:match:d5fa770e', '4-2-quality-of-goods-services', '4.2 Quality of Goods & Services', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Culture of Quality”?", "options": ["Goods that fail quality inspection but can still be sold to customers at a reduced price, resulting in lower revenue for the business.", "A product or service that is fit for purpose, meets legislative rules, and meets customer expectations.", "A system for inspecting the quality of goods or services produced by specialist inspectors to ensure they meet a good standard.", "An environment in a business where every employee at every level takes personal responsibility for maintaining quality standards."]}'::jsonb, '{"answer": 3, "explain": "“Culture of Quality” means: An environment in a business where every employee at every level takes personal responsibility for maintaining quality standards."}'::jsonb),
('4-2-quality-of-goods-services:match:e012d666', '4-2-quality-of-goods-services', '4.2 Quality of Goods & Services', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Seconds”?", "options": ["Goods that fail quality inspection but can still be sold to customers at a reduced price, resulting in lower revenue for the business.", "A product or service that is fit for purpose, meets legislative rules, and meets customer expectations.", "A system for inspecting the quality of goods or services produced by specialist inspectors to ensure they meet a good standard.", "An approach that involves the whole business focusing on quality, aiming to prevent quality problems from arising at every stage of production."]}'::jsonb, '{"answer": 0, "explain": "“Seconds” means: Goods that fail quality inspection but can still be sold to customers at a reduced price, resulting in lower revenue for the business."}'::jsonb),
('4-3-sales-process-customer-service:exam:bc125adf', '4-3-sales-process-customer-service', '4.3 The Sales Process', 'exam', 'mcq', 1, '{"num": "Q2", "question": "Which of the following is an advantage to the manufacturer of selling face to face to jewellery stores?", "options": ["The cut and colour of the diamonds can be clearly demonstrated", "The jewellery stores have the opportunity to negotiate very low prices", "The risk of the rings being stolen is kept as low as possible", "The sales staff can give out lots of free samples"], "caseStudy": "A manufacturer of diamond rings employs sales staff to visit jewellery stores across the UK to encourage them to purchase its products.", "hint": "Think about what face-to-face selling uniquely allows that e-commerce or telesales cannot — particularly for a high-value, visual product like diamond rings.", "starter": "The correct answer is A because..."}'::jsonb, '{"answer": 0, "markScheme": "<div class=\"marks-section\"><h5>Answer: A</h5>\n<p><strong>A — The cut and colour of the diamonds can be clearly demonstrated.</strong></p>\n<p><strong>Why A is correct:</strong> Face-to-face selling allows the physical product to be examined in person. For diamond rings, where cut, colour, clarity, and craftsmanship are key selling points, a live demonstration is far more effective than an image or telephone description.</p>\n<p><strong>Why the others are wrong:</strong></p>\n<ul>\n<li><strong>B — Negotiating very low prices</strong> is a benefit to the BUYER (jewellery stores), not the manufacturer/seller.</li>\n<li><strong>C — Reducing theft risk</strong> is not a specific or notable advantage of face-to-face selling over other methods.</li>\n<li><strong>D — Free samples</strong> are not realistic for diamond rings, and giving away samples is not a defining feature of face-to-face selling.</li>\n</ul></div>", "modelAnswer": ""}'::jsonb),
('4-3-sales-process-customer-service:exam:b76b0eac', '4-3-sales-process-customer-service', '4.3 The Sales Process', 'exam', 'mcq', 1, '{"num": "Q6", "question": "Customer engagement:", "options": ["Allows customers to try before they buy", "Contributes to good customer service", "Improves the product knowledge of employees", "Shortens the supply chain"], "hint": "Think about the official definition of customer engagement — what does it directly contribute to in a business?", "starter": "The correct answer is B because..."}'::jsonb, '{"answer": 1, "markScheme": "<div class=\"marks-section\"><h5>Answer: B</h5>\n<p><strong>B — Contributes to good customer service.</strong></p>\n<p><strong>Why B is correct:</strong> Customer engagement (the contact between business and customer) is one of the key ways a business delivers good customer service — well-trained, engaged staff build loyalty and improve customer satisfaction.</p>\n<p><strong>Why the others are wrong:</strong></p>\n<ul>\n<li><strong>A — Trying before buying</strong> is a feature of face-to-face retail, not customer engagement per se.</li>\n<li><strong>C — Improving product knowledge of employees</strong> is about staff training, not customer engagement.</li>\n<li><strong>D — Shortening the supply chain</strong> is a logistics and procurement concept, unrelated to customer engagement.</li>\n</ul>\n<p><strong>Examiner''s Comment:</strong> Some students showed misunderstanding of ''customer engagement''. Always take time to read what the question is actually asking.</p></div>", "modelAnswer": ""}'::jsonb),
('4-3-sales-process-customer-service:exam:cd3a5e94', '4-3-sales-process-customer-service', '4.3 The Sales Process', 'exam', 'mcq', 1, '{"num": "Q8", "question": "Which of the following would help Geoff deal with this problem?", "options": ["Advertise other second-hand book shops in the area", "Close the shop early on weekdays in the school holidays", "Improve customer service by being friendly and polite", "Offer a free book to new customers who spend over £5"], "caseStudy": "Geoff, a sole trader, owns a second-hand book shop. Despite being well advertised and selling reasonably priced products, the shop has difficulty retaining customers.", "hint": "Geoff can gain customers (advertising is working and prices are good) but cannot KEEP them. Which option directly addresses the post-purchase experience and encourages customers to return?", "starter": "The correct answer is C because..."}'::jsonb, '{"answer": 2, "markScheme": "<div class=\"marks-section\"><h5>Answer: C</h5>\n<p><strong>C — Improve customer service by being friendly and polite.</strong></p>\n<p><strong>Why C is correct:</strong> The shop is advertised and prices are reasonable — marketing and pricing are not the issue. The problem is RETENTION. Friendly, polite customer service improves the experience and gives customers a reason to return.</p>\n<p><strong>Why the others are wrong:</strong></p>\n<ul>\n<li><strong>A — Advertising other book shops</strong> would actively help competitors and drive customers away from Geoff''s shop.</li>\n<li><strong>B — Closing early</strong> reduces accessibility and would make retention worse, not better.</li>\n<li><strong>D — Free book for new customers</strong> targets gaining NEW customers, but the problem stated is retaining EXISTING ones.</li>\n</ul></div>", "modelAnswer": ""}'::jsonb),
('4-3-sales-process-customer-service:exam:88ea4383', '4-3-sales-process-customer-service', '4.3 The Sales Process', 'exam', 'mcq', 1, '{"num": "Q9", "question": "This is an example of:", "options": ["After-sales service", "E-commerce", "Face to face selling", "Telesales"], "caseStudy": "An assistant serves a customer who has come into the post office to top-up their mobile phone credit.", "hint": "The customer physically enters a building and is served in person. Which method of selling involves direct contact between buyer and seller in a physical location?", "starter": "The correct answer is C because..."}'::jsonb, '{"answer": 2, "markScheme": "<div class=\"marks-section\"><h5>Answer: C</h5>\n<p><strong>C — Face to face selling.</strong></p>\n<p><strong>Why C is correct:</strong> The customer visits a physical location (post office) and is served directly by an assistant — direct contact between buyer and seller defines face-to-face selling.</p>\n<p><strong>Why the others are wrong:</strong></p>\n<ul>\n<li><strong>A — After-sales service</strong> is advice or help AFTER a purchase has already been made, not at the point of sale.</li>\n<li><strong>B — E-commerce</strong> involves buying and selling electronically — there is no online element here.</li>\n<li><strong>D — Telesales</strong> is completed over the telephone — the customer is physically present, not calling.</li>\n</ul></div>", "modelAnswer": ""}'::jsonb),
('4-3-sales-process-customer-service:exam:8467913c', '4-3-sales-process-customer-service', '4.3 The Sales Process', 'exam', 'mcq', 1, '{"num": "Q11", "question": "Which aspect of the business is most likely to need improving?", "options": ["After-sales service", "E-commerce", "Marketing", "Procurement"], "caseStudy": "A business finds it relatively easy to gain customers but has great difficulty retaining these customers.", "hint": "The business gains customers easily — so what is already working? The problem is keeping customers AFTER their first purchase. Which aspect deals with the post-purchase experience?", "starter": "The correct answer is A because..."}'::jsonb, '{"answer": 0, "markScheme": "<div class=\"marks-section\"><h5>Answer: A</h5>\n<p><strong>A — After-sales service.</strong></p>\n<p><strong>Why A is correct:</strong> Marketing (C) is clearly working — the business gains customers easily. The problem is RETENTION. After-sales service determines how customers are treated after a purchase — poor after-sales service leads to customers not returning.</p>\n<p><strong>Why the others are wrong:</strong></p>\n<ul>\n<li><strong>B — E-commerce</strong> relates to the selling method, not to why customers stop returning.</li>\n<li><strong>C — Marketing</strong> is what gains customers — the question confirms this is already working well.</li>\n<li><strong>D — Procurement</strong> relates to buying supplies and inputs, not customer retention.</li>\n</ul></div>", "modelAnswer": ""}'::jsonb),
('4-3-sales-process-customer-service:exam:8d7b6d8f', '4-3-sales-process-customer-service', '4.3 The Sales Process', 'exam', 'mcq', 1, '{"num": "Q13", "question": "Which one of the following will NOT improve the level of customer service the store offers?", "options": ["Demonstrating to all staff how to be attentive, polite and helpful", "Giving the sales assistants lists detailing the features of each phone", "Offering a free phone case with every mobile phone purchased", "Training the store manager to deal with technical queries"], "caseStudy": "A store that sells mobile phones wishes to improve the level of customer service it offers to those who come into the store.", "hint": "Think about what customer service actually means — the quality of interaction, advice, and assistance provided. Which option is a promotional or pricing decision rather than a customer service improvement?", "starter": "The correct answer is C because..."}'::jsonb, '{"answer": 2, "markScheme": "<div class=\"marks-section\"><h5>Answer: C</h5>\n<p><strong>C — Offering a free phone case with every mobile phone purchased.</strong></p>\n<p><strong>Why C is correct:</strong> A free phone case is a sales promotion / pricing incentive. It may attract customers, but it does not improve the QUALITY of service, advice, or interaction customers receive in store.</p>\n<p><strong>Why the others are wrong (they DO improve customer service):</strong></p>\n<ul>\n<li><strong>A</strong> — Training staff to be attentive and polite directly improves customer engagement — a key part of customer service.</li>\n<li><strong>B</strong> — Giving staff product feature lists improves product knowledge, enabling better advice for customers.</li>\n<li><strong>D</strong> — Training the manager to handle technical queries improves after-sales service and the ability to resolve customer problems effectively.</li>\n</ul></div>", "modelAnswer": ""}'::jsonb),
('4-3-sales-process-customer-service:exam:4c1aa491', '4-3-sales-process-customer-service', '4.3 The Sales Process', 'exam', 'mcq', 1, '{"num": "Q16", "question": "What is e-commerce?", "options": ["A method used to ensure quality", "A planning tool", "A type of bank loan", "A way to sell goods on the Internet"], "hint": "Think about the official definition — e-commerce involves buying and selling using internet technology.", "starter": "The correct answer is D because..."}'::jsonb, '{"answer": 3, "markScheme": "<div class=\"marks-section\"><h5>Answer: D</h5>\n<p><strong>D — A way to sell goods on the Internet.</strong></p>\n<p><strong>Why D is correct:</strong> E-commerce is the bringing together of buying and selling electronically — commonly known as online sales via the internet.</p>\n<p><strong>Why the others are wrong:</strong></p>\n<ul>\n<li><strong>A</strong> — Quality control and quality assurance are methods to ensure quality, not e-commerce.</li>\n<li><strong>B</strong> — Planning tools include cash flow forecasts and SWOT analysis, not e-commerce.</li>\n<li><strong>C</strong> — A bank loan is a source of finance, completely unrelated to e-commerce.</li>\n</ul></div>", "modelAnswer": ""}'::jsonb),
('4-3-sales-process-customer-service:exam:c6d615df', '4-3-sales-process-customer-service', '4.3 The Sales Process', 'exam', 'mcq', 1, '{"num": "Q17", "question": "Which one of the following businesses is most likely to use telesales?", "options": ["A burger van", "A petrol station", "A school", "An insurance company"], "hint": "Think about which type of business primarily sells its products or services by phone — where customers call to get a quote, renew a policy, or make a purchase without needing to see anything in person.", "starter": "The correct answer is D because..."}'::jsonb, '{"answer": 3, "markScheme": "<div class=\"marks-section\"><h5>Answer: D</h5>\n<p><strong>D — An insurance company.</strong></p>\n<p><strong>Why D is correct:</strong> Insurance companies are classic users of telesales — customers call to get quotes, compare options, negotiate premiums, and renew policies over the phone. The product (insurance) is intangible and requires no physical demonstration, making telephone sales ideal.</p>\n<p><strong>Why the others are wrong:</strong></p>\n<ul>\n<li><strong>A</strong> — A burger van sells face-to-face at a physical location to passing customers.</li>\n<li><strong>B</strong> — A petrol station sells face-to-face at a physical location.</li>\n<li><strong>C</strong> — A school provides education services rather than selling products through telesales.</li>\n</ul></div>", "modelAnswer": ""}'::jsonb),
('4-3-sales-process-customer-service:exam:137940c2', '4-3-sales-process-customer-service', '4.3 The Sales Process', 'exam', 'mcq', 1, '{"num": "Q19", "question": "Which of the following is this an example of?", "options": ["Face to face selling", "International branding", "Sales promotion", "Telesales"], "caseStudy": "A customer comes into a travel agency to book a holiday to Australia. An assistant serves the customer.", "hint": "The customer physically visits a location and is served in person. Which method of selling is defined by direct physical contact between buyer and seller?", "starter": "The correct answer is A because..."}'::jsonb, '{"answer": 0, "markScheme": "<div class=\"marks-section\"><h5>Answer: A</h5>\n<p><strong>A — Face to face selling.</strong></p>\n<p><strong>Why A is correct:</strong> The customer physically enters the travel agency and is served directly by an assistant — direct contact between buyer and seller in a physical setting is the definition of face-to-face selling.</p>\n<p><strong>Why the others are wrong:</strong></p>\n<ul>\n<li><strong>B — International branding</strong> refers to developing a brand identity across countries, not a method of selling.</li>\n<li><strong>C — Sales promotion</strong> refers to short-term marketing incentives (discounts, offers), not the method of selling.</li>\n<li><strong>D — Telesales</strong> would require the customer to be on the phone, not physically present.</li>\n</ul></div>", "modelAnswer": ""}'::jsonb),
('4-3-sales-process-customer-service:exam:9b8efc96', '4-3-sales-process-customer-service', '4.3 The Sales Process', 'exam', 'mcq', 1, '{"num": "Q20", "question": "Which of the following will NOT improve customer engagement?", "options": ["Training staff on the benefit of coconuts", "Only selling products that have been certified as organic", "Sending carefully worded personalised emails to interested customers", "Sending text messages to all previous customers about the benefits of coconut oil"], "caseStudy": "Coconut Life uses e-commerce to sell its range of innovative coconut products.", "hint": "Customer engagement is about improving the CONTACT between the business and its customers. Which option is a product sourcing or quality decision rather than a communication or interaction improvement?", "starter": "The correct answer is B because..."}'::jsonb, '{"answer": 1, "markScheme": "<div class=\"marks-section\"><h5>Answer: B</h5>\n<p><strong>B — Only selling products that have been certified as organic.</strong></p>\n<p><strong>Why B is correct:</strong> This is a product sourcing or quality decision — it may influence what is sold, but it does NOT directly improve the CONTACT or interaction between Coconut Life and its customers. Customer engagement requires active communication and connection.</p>\n<p><strong>Why the others are wrong (they DO improve engagement):</strong></p>\n<ul>\n<li><strong>A</strong> — Training staff improves their ability to advise and connect with customers when interacting with them.</li>\n<li><strong>C</strong> — Personalised emails are a direct, thoughtful form of customer contact and engagement.</li>\n<li><strong>D</strong> — Text messages to previous customers are a form of ongoing contact and engagement.</li>\n</ul>\n<p><strong>Examiner''s Comment:</strong> Some students misunderstood ''customer engagement''. Also note this question asks what will NOT improve it — always check whether you are looking for the item that will or will not do something.</p></div>", "modelAnswer": ""}'::jsonb),
('4-3-sales-process-customer-service:exam:c1a940fe', '4-3-sales-process-customer-service', '4.3 The Sales Process', 'exam', 'mcq', 1, '{"num": "JCM Q1", "question": "Face-to-face selling involves:", "options": ["Advertising goods on a website", "A buyer meeting with a seller", "A seller telephoning buyers to ask them if they want to buy", "Using a website to take orders from customers"], "caseStudy": "JC Motors Ltd have been trading for 10 years. They specialise in selling high-end bespoke cars that start from £50,000 and can be as expensive as £300,000. They are renowned for their excellent customer service as they are always willing to go the extra mile to make customers feel special. Customers are offered a wide range of hot drinks and snacks on arrival that is served to them in the luxurious seating area. Children can be kept entertained with miniature electric cars that they can drive around the specially designed track. The staff have excellent knowledge about each car and are always available following the purchase of the car to answer any queries. JC Motors Ltd have also sold several cars to customers worldwide owing to their website that offers to ship their cars around the globe.", "hint": "What is the one defining feature of face-to-face selling that makes it different from all other methods?", "starter": "The correct answer is B because..."}'::jsonb, '{"answer": 1, "markScheme": "<div class=\"marks-section\"><h5>Answer: B</h5>\n<p><strong>B — A buyer meeting with a seller.</strong></p>\n<p><strong>Why B is correct:</strong> Face-to-face selling requires direct physical contact between buyer and seller — they meet in person. This is what makes it distinctly different from all other selling methods.</p>\n<p><strong>Why the others are wrong:</strong></p>\n<ul>\n<li><strong>A — Advertising on a website</strong> is digital marketing, not a selling method involving personal contact.</li>\n<li><strong>C — Telephoning buyers</strong> describes telesales, not face-to-face selling.</li>\n<li><strong>D — Using a website to take orders</strong> describes e-commerce.</li>\n</ul></div>", "modelAnswer": ""}'::jsonb),
('4-3-sales-process-customer-service:mcq:102c3de8', '4-3-sales-process-customer-service', '4.3 The Sales Process', 'mcq', 'mcq', 1, '{"question": "Which of the following is the correct definition of e-commerce?", "options": ["The buying and selling of goods in a physical shop", "The bringing together of buying and selling electronically", "Selling goods over the telephone", "The delivery of goods using drones"]}'::jsonb, '{"answer": 1, "explain": "Correct answer: B. E-commerce is specifically defined as the bringing together of buying and selling electronically (online sales). It always involves some form of physical delivery after the online sale — unlike digital distribution where the product itself is delivered digitally."}'::jsonb),
('4-3-sales-process-customer-service:mcq:163695bc', '4-3-sales-process-customer-service', '4.3 The Sales Process', 'mcq', 'mcq', 1, '{"question": "Which of the following is an advantage to a BUSINESS of using e-commerce?", "options": ["Customers can compare prices easily across multiple websites", "Customers can shop at any time of day or night", "Lower operating costs as no expensive shop premises are needed", "Customers can touch and examine products before buying"]}'::jsonb, '{"answer": 2, "explain": "Correct answer: C. Lower operating costs is an advantage to the BUSINESS — no need to pay expensive city-centre rents. Options A, B, and D are advantages to CUSTOMERS, not businesses. Always check whose perspective the question is asking about."}'::jsonb),
('4-3-sales-process-customer-service:mcq:aed68eb6', '4-3-sales-process-customer-service', '4.3 The Sales Process', 'mcq', 'mcq', 1, '{"question": "Customer engagement refers to:", "options": ["Allowing customers to try products before they buy", "The contact between the business and customer", "Improving the product knowledge of employees", "Shortening the supply chain"]}'::jsonb, '{"answer": 1, "explain": "Correct answer: B. Customer engagement is defined as the contact between the business and customer. This includes face-to-face interaction in stores, friendly voices in telesales, and carefully worded emails/texts in e-commerce."}'::jsonb),
('4-3-sales-process-customer-service:mcq:7097e35e', '4-3-sales-process-customer-service', '4.3 The Sales Process', 'mcq', 'mcq', 1, '{"question": "A business finds it easy to gain customers but has difficulty retaining them. Which aspect of the business most likely needs improving?", "options": ["After-sales service", "E-commerce", "Marketing", "Procurement"]}'::jsonb, '{"answer": 0, "explain": "Correct answer: A. After-sales service. Marketing (C) is clearly working — it is attracting customers. The problem is what happens AFTER the sale. After-sales service keeps customers satisfied and coming back."}'::jsonb),
('4-3-sales-process-customer-service:mcq:d979aab1', '4-3-sales-process-customer-service', '4.3 The Sales Process', 'mcq', 'mcq', 1, '{"question": "Face to face selling will help a business most when:", "options": ["The goods being sold are cheap and simple", "Service and advice are important to the customer", "The customer has a computer and internet access", "The goods are small and easily transported"]}'::jsonb, '{"answer": 1, "explain": "Correct answer: B. Face to face selling is most valuable when service matters — for example, buying a wedding dress, complex electronics, or financial products. The physical presence of staff allows advice, demonstrations, and relationship-building that e-commerce cannot fully replicate."}'::jsonb),
('4-3-sales-process-customer-service:mcq:9f6546a6', '4-3-sales-process-customer-service', '4.3 The Sales Process', 'mcq', 'mcq', 1, '{"question": "Which of the following is a disadvantage to CUSTOMERS of using e-commerce?", "options": ["Having to pay expensive city-centre rents", "Increased worldwide competition from other businesses", "Difficulty keeping up with advances in technology costs", "Inability to touch or inspect products before purchasing"]}'::jsonb, '{"answer": 3, "explain": "Correct answer: D. Only being able to see images of goods (not touch or inspect them) is a disadvantage to the CUSTOMER. Options A (rents), B (competition), and C (technology update costs) are all disadvantages to BUSINESSES using e-commerce."}'::jsonb),
('4-3-sales-process-customer-service:mcq:76661270', '4-3-sales-process-customer-service', '4.3 The Sales Process', 'mcq', 'mcq', 1, '{"question": "Why is good product knowledge important to a business?", "options": ["It helps recruit better staff to the business", "It will help a business in the sales process", "It will develop better working conditions for staff", "It will mean that training costs are lower"]}'::jsonb, '{"answer": 1, "explain": "Correct answer: B. Good product knowledge helps staff in the sales process by allowing them to advise customers confidently, increasing the chance of a purchase. It does NOT reduce training costs (D) — in fact, gaining product knowledge requires investment in training."}'::jsonb),
('4-3-sales-process-customer-service:mcq:ca827ea1', '4-3-sales-process-customer-service', '4.3 The Sales Process', 'mcq', 'mcq', 1, '{"question": "Click and collect is best described as:", "options": ["Buying goods in a shop and having them delivered to your home", "Ordering goods online and collecting them from a store at a later time", "Using a phone to order goods from a telesales department", "Returning faulty goods to a warehouse after an online purchase"]}'::jsonb, '{"answer": 1, "explain": "Correct answer: B. Click and collect means ordering online and collecting goods from a store later. It solves the problem of customers not being home for delivery, while ensuring the product is in stock before the customer makes the journey."}'::jsonb),
('4-3-sales-process-customer-service:mcq:5945327a', '4-3-sales-process-customer-service', '4.3 The Sales Process', 'mcq', 'mcq', 1, '{"question": "Which of the following businesses is most likely to use telesales as a primary method of selling?", "options": ["A burger van", "A petrol station", "A school", "An insurance company"]}'::jsonb, '{"answer": 3, "explain": "Correct answer: D. An insurance company commonly uses telesales — customers call to get quotes, renew policies, or negotiate better deals. Burger vans (A) and petrol stations (B) use face-to-face selling, and schools (C) do not sell products in the conventional sense."}'::jsonb),
('4-3-sales-process-customer-service:mcq:f2bb1ff4', '4-3-sales-process-customer-service', '4.3 The Sales Process', 'mcq', 'mcq', 1, '{"question": "A manufacturer of diamond rings employs staff to visit jewellery stores. Which is an advantage to the manufacturer of selling face to face?", "options": ["The cut and colour of the diamonds can be clearly demonstrated", "The jewellery stores have the opportunity to negotiate very low prices", "The risk of the rings being stolen is kept as low as possible", "The sales staff can give out lots of free samples"]}'::jsonb, '{"answer": 0, "explain": "Correct answer: A. Face-to-face selling allows the physical product to be demonstrated and examined — crucial for diamond rings where cut, colour, and quality must be seen in person. Option B (negotiating low prices) is a benefit to the BUYER, not the manufacturer."}'::jsonb),
('4-3-sales-process-customer-service:mcq:a0a4ee55', '4-3-sales-process-customer-service', '4.3 The Sales Process', 'mcq', 'mcq', 1, '{"question": "Which of the following will NOT improve customer engagement for an e-commerce business?", "options": ["Training staff on the benefits of the product range", "Only selling products that have been certified as organic", "Sending carefully worded personalised emails to interested customers", "Sending text messages to previous customers about new products"]}'::jsonb, '{"answer": 1, "explain": "Correct answer: B. Only selling certified organic products is a product/sourcing decision — it does not directly improve the CONTACT between the business and customer. Options A, C, and D all directly improve how the business communicates and connects with its customers."}'::jsonb),
('4-3-sales-process-customer-service:mcq:2da87c1d', '4-3-sales-process-customer-service', '4.3 The Sales Process', 'mcq', 'mcq', 1, '{"question": "Which of the following would help a sole trader whose shop has difficulty RETAINING customers?", "options": ["Advertise other competing shops in the local area", "Close the shop early on weekdays in the school holidays", "Improve customer service by being friendly and polite", "Offer a free item to new customers who spend over a threshold"]}'::jsonb, '{"answer": 2, "explain": "Correct answer: C. If the shop is advertised and prices are reasonable, the problem is RETENTION. Customer service (being friendly and polite) improves customer engagement and gives customers a reason to return. Option D attracts NEW customers, not retains existing ones."}'::jsonb),
('4-3-sales-process-customer-service:tf:aae3992f', '4-3-sales-process-customer-service', '4.3 The Sales Process', 'tf', 'tf', 1, '{"question": "E-commerce involves some form of physical delivery after an online sale."}'::jsonb, '{"answer": true, "explain": "TRUE. This is what distinguishes e-commerce from digital distribution — with e-commerce, the product is still physically delivered to the customer after being purchased online."}'::jsonb),
('4-3-sales-process-customer-service:tf:61b2b741', '4-3-sales-process-customer-service', '4.3 The Sales Process', 'tf', 'tf', 1, '{"question": "A business using e-commerce must always be located near a city centre."}'::jsonb, '{"answer": false, "explain": "FALSE. E-commerce businesses can locate almost anywhere. The ''front end'' (order taking) only requires an internet connection, and the warehouse simply needs to be near good transport links like a motorway network for efficient delivery."}'::jsonb),
('4-3-sales-process-customer-service:tf:9751e68f', '4-3-sales-process-customer-service', '4.3 The Sales Process', 'tf', 'tf', 1, '{"question": "After-sales service is only important if a product is legally required to come with a guarantee."}'::jsonb, '{"answer": false, "explain": "FALSE. After-sales service is important regardless of legal requirements. Businesses that offer refunds or resolve problems (even when not legally required to) build customer loyalty and encourage repeat purchases."}'::jsonb),
('4-3-sales-process-customer-service:tf:d9b2e8b9', '4-3-sales-process-customer-service', '4.3 The Sales Process', 'tf', 'tf', 1, '{"question": "Telesales can be a useful method of selling to older customers who are less comfortable with online shopping."}'::jsonb, '{"answer": true, "explain": "TRUE. Telesales bridges the gap between e-commerce and face-to-face selling. Customers who are not comfortable using the internet may be very happy to talk to someone on the phone and be guided through the buying process."}'::jsonb),
('4-3-sales-process-customer-service:tf:62073e4c', '4-3-sales-process-customer-service', '4.3 The Sales Process', 'tf', 'tf', 1, '{"question": "A business with a well-designed website will always provide better customer engagement than a physical shop."}'::jsonb, '{"answer": false, "explain": "FALSE. A website creates a professional image, but customer engagement — the contact between business and customer — is often stronger in face-to-face settings where staff can directly answer questions, demonstrate products, and build personal relationships."}'::jsonb),
('4-3-sales-process-customer-service:tf:d1113c4a', '4-3-sales-process-customer-service', '4.3 The Sales Process', 'tf', 'tf', 1, '{"question": "Click and collect has meant that businesses need to dedicate more in-store space for collection points."}'::jsonb, '{"answer": true, "explain": "TRUE. The success of click and collect has led businesses to allocate dedicated floor space for collection customers inside their stores, affecting how the available space is used overall."}'::jsonb),
('4-3-sales-process-customer-service:tf:7df1ce1a', '4-3-sales-process-customer-service', '4.3 The Sales Process', 'tf', 'tf', 1, '{"question": "E-commerce always reduces the number of employees a business needs."}'::jsonb, '{"answer": false, "explain": "FALSE. The effect on employment depends on the situation. An existing business switching to e-commerce may reduce staff in branches. But a new e-commerce business must recruit warehouse staff, website managers, and customer service representatives."}'::jsonb),
('4-3-sales-process-customer-service:tf:adcbe72e', '4-3-sales-process-customer-service', '4.3 The Sales Process', 'tf', 'tf', 1, '{"question": "Online security is only a concern for customers, not for businesses using e-commerce."}'::jsonb, '{"answer": false, "explain": "FALSE. Security is a concern for BOTH customers AND businesses. Businesses must operate a secure website and keep customer data safe. A security breach damages customer trust and can result in significant financial costs and reputational harm."}'::jsonb),
('4-3-sales-process-customer-service:tf:2656ae09', '4-3-sales-process-customer-service', '4.3 The Sales Process', 'tf', 'tf', 1, '{"question": "Product knowledge is equally important in all types of businesses."}'::jsonb, '{"answer": false, "explain": "FALSE. The importance of product knowledge varies by context. It is highly important in electronics stores or garden centres where customers need expert advice. It is relatively less critical in, for example, a newsagent."}'::jsonb),
('4-3-sales-process-customer-service:tf:f921101d', '4-3-sales-process-customer-service', '4.3 The Sales Process', 'tf', 'tf', 1, '{"question": "Amazon focuses more on pricing, choice, and speed of delivery than on face-to-face customer engagement."}'::jsonb, '{"answer": true, "explain": "TRUE. Amazon competes primarily through price, product range, and delivery speed (Amazon Prime). John Lewis, by contrast, relies on face-to-face customer engagement and product knowledge in its stores."}'::jsonb),
('4-3-sales-process-customer-service:tf:7a4c9340', '4-3-sales-process-customer-service', '4.3 The Sales Process', 'tf', 'tf', 1, '{"question": "Cold calling (unsolicited telesales) is generally viewed positively by customers."}'::jsonb, '{"answer": false, "explain": "FALSE. Cold calling is widely seen as a nuisance by many customers, particularly when calls arrive at inconvenient times. This is a growing issue with telesales as a selling method."}'::jsonb),
('4-3-sales-process-customer-service:tf:b64eb83c', '4-3-sales-process-customer-service', '4.3 The Sales Process', 'tf', 'tf', 1, '{"question": "E-commerce can help a small business compete with much larger firms on a global scale."}'::jsonb, '{"answer": true, "explain": "TRUE. E-commerce allows even the smallest business to reach a worldwide market with a professional-looking website at relatively low cost — competing on a scale that would not have been possible through traditional retail."}'::jsonb),
('4-3-sales-process-customer-service:learn:9efa567d', '4-3-sales-process-customer-service', '4.3 The Sales Process', 'learn', 'mcq', 1, '{"readingTitle": "Key Terms & Official Definitions", "reading": "<p>These are the essential terms you must know for 4.3. Learn them precisely — examiners reward specific, accurate definitions.</p>\n<ul>\n<li><strong>E-commerce:</strong> The bringing together of buying and selling electronically (online sales).</li>\n<li><strong>Customer service:</strong> The name given to an area of business that deals with customer enquiries.</li>\n<li><strong>Customer engagement:</strong> The contact between the business and customer.</li>\n<li><strong>Click and collect:</strong> Ordering online and collecting goods from store at a later time.</li>\n<li><strong>Face to face selling:</strong> Usually completed in a shop where there is direct contact between buyer and seller.</li>\n<li><strong>Telesales:</strong> Sales completed over the telephone.</li>\n<li><strong>After-sales service:</strong> Advice and help given to a customer after they have bought a product or service.</li>\n<li><strong>Product knowledge:</strong> The detailed knowledge of a product or service that staff within a business use to help persuade a customer to buy.</li>\n</ul>", "question": "According to the key terms, what is ''customer engagement''?", "options": ["The contact between the business and customer", "The area of business dealing with customer enquiries", "Advice given to a customer after a purchase", "Direct contact between buyer and seller in a shop"]}'::jsonb, '{"answer": 0, "explain": "Customer engagement is defined precisely as ''the contact between the business and customer'' — distinct from customer service (enquiries) or after-sales service (post-purchase advice)."}'::jsonb),
('4-3-sales-process-customer-service:learn:2c187692', '4-3-sales-process-customer-service', '4.3 The Sales Process', 'learn', 'mcq', 1, '{"readingTitle": "Methods of Selling", "reading": "<p>Businesses can use a range of selling methods depending on the product, target market, and business size. The three main methods are:</p>\n<ul>\n<li><strong>E-commerce:</strong> Bringing a buyer and seller together electronically. Involves physical delivery after an online sale.</li>\n<li><strong>Face to face:</strong> Direct contact between buyer and seller, typically in a shop, bank, or travel agent. Allows advice and interaction.</li>\n<li><strong>Telesales:</strong> Sales completed over the telephone. Acts as a bridge between e-commerce and face to face, especially useful for customers less comfortable with the internet.</li>\n</ul>\n<p>Not all businesses are suited to every method. The best method depends on the <strong>product type</strong>, the <strong>target market</strong>, and the level of <strong>service</strong> required.</p>\n<div class=\"case-study-box\">\n<h4>Case Study: John Lewis & Partners</h4>\n<p>John Lewis uses all three methods. Its department stores use face-to-face selling with trained staff who have excellent product knowledge, particularly in electronics. It also has a fast-growing e-commerce operation and uses phone lines for customer queries. JLP''s strategy shows how a business can combine multiple selling methods to serve different customers effectively.</p>\n</div>", "question": "Which company, according to the case study, uses all three selling methods (face-to-face, e-commerce, and telesales)?", "options": ["John Lewis Partners", "Amazon UK Ltd", "JC Motors Ltd", "Marks & Spencer"]}'::jsonb, '{"answer": 0, "explain": "The case study states John Lewis uses face-to-face selling in stores, a fast-growing e-commerce operation, and phone lines for customer queries."}'::jsonb),
('4-3-sales-process-customer-service:learn:611b30b5', '4-3-sales-process-customer-service', '4.3 The Sales Process', 'learn', 'mcq', 1, '{"readingTitle": "The Influence of E-commerce on Business Activity", "reading": "<p>The growth of e-commerce — accelerated dramatically during the COVID-19 pandemic of 2020–21 — has changed business activity in several key ways:</p>\n<ul>\n<li><strong>Location:</strong> Businesses can locate almost anywhere. A telephone/internet connection handles the \"front end\" (orders), while warehouses can be separately sited near motorway networks for fast delivery.</li>\n<li><strong>New skill development:</strong> Staff need new skills — website maintenance, email responses, warehouse packing. Extra training may be required at all levels.</li>\n<li><strong>Levels of employment:</strong> E-commerce may increase OR decrease employment. Existing businesses may need fewer branch staff (e.g. banks), but new e-commerce startups must recruit website, logistics, and customer service staff.</li>\n<li><strong>Creation of specific departments:</strong> Large businesses like M&S, Next, and John Lewis have set up dedicated online departments to manage e-commerce sales and avoid losing business to competitors.</li>\n<li><strong>Click and collect:</strong> Customers order online and collect in-store later, solving the \"not home for delivery\" problem. Stores must dedicate space for click and collect areas.</li>\n<li><strong>Delivery options:</strong> Speed of delivery is a key competitive area. Amazon Prime offers next-day and same-day delivery. Drone delivery is a future possibility but faces security and safety hurdles.</li>\n</ul>", "question": "What historic event is identified as dramatically accelerating e-commerce growth?", "options": ["The COVID-19 pandemic of 2020–21", "The 2008 financial crisis", "The launch of Amazon Prime", "The invention of the smartphone"]}'::jsonb, '{"answer": 0, "explain": "The card states the growth of e-commerce was ''accelerated dramatically during the COVID-19 pandemic of 2020–21''."}'::jsonb),
('4-3-sales-process-customer-service:learn:efa9b50a', '4-3-sales-process-customer-service', '4.3 The Sales Process', 'learn', 'mcq', 1, '{"readingTitle": "Advantages & Disadvantages of E-commerce for Businesses", "reading": "<p>When evaluating e-commerce, always check whether the question asks for the <strong>business''s</strong> perspective or the <strong>customer''s</strong> perspective. Mixing these up is one of the most common reasons students lose marks.</p>\n<div class=\"two-col\">\n<div>\n<div class=\"col-head\">✓ Advantages for Businesses</div>\n<div class=\"pro-item\"><strong>Sell worldwide:</strong> Even the smallest business can reach a global market, significantly increasing the potential customer base, sales, and profit.</div>\n<div class=\"pro-item\"><strong>Open all the time:</strong> No restriction on opening hours — the business can generate sales 24 hours a day, 7 days a week.</div>\n<div class=\"pro-item\"><strong>Professional look at little cost:</strong> A well-designed website creates a strong brand image, attracting customers without the need for expensive premises.</div>\n<div class=\"pro-item\"><strong>Lower operating costs:</strong> No need to pay expensive city-centre rents. The business can operate from anywhere with an internet connection, keeping profits high.</div>\n</div>\n<div>\n<div class=\"col-head\">✗ Disadvantages for Businesses</div>\n<div class=\"con-item\"><strong>Worldwide competition:</strong> All e-commerce businesses face global competitors. Customers can easily compare prices, putting downward pressure on margins.</div>\n<div class=\"con-item\"><strong>Problems of delivering goods and accepting returns:</strong> Reliance on third-party logistics adds cost. High return rates increase expenses further.</div>\n<div class=\"con-item\"><strong>Online security:</strong> Businesses must maintain a secure website and keep customer data safe. A breach destroys customer trust and adds significant costs.</div>\n<div class=\"con-item\"><strong>Advances in technology:</strong> Businesses must constantly update their technology (e.g. mobile-optimised sites) to keep up with customer buying habits. This is ongoing and costly.</div>\n</div>\n</div>", "question": "Which of these is listed as a disadvantage of e-commerce FOR BUSINESSES (not customers)?", "options": ["Worldwide competition puts downward pressure on margins", "Customers cannot touch or try products before buying", "Payment is geared towards card/debit only", "Restricted shop opening hours"]}'::jsonb, '{"answer": 0, "explain": "The business disadvantages list worldwide competition and easy price comparison putting downward pressure on margins; the other options are customer-side issues."}'::jsonb),
('4-3-sales-process-customer-service:learn:0a2a3856', '4-3-sales-process-customer-service', '4.3 The Sales Process', 'learn', 'mcq', 1, '{"readingTitle": "Advantages & Disadvantages of E-commerce for Customers", "reading": "<p>Customers experience both benefits and drawbacks from e-commerce. Remember — some exam questions specifically ask about the <strong>customer''s</strong> perspective, not the business''s.</p>\n<div class=\"two-col\">\n<div>\n<div class=\"col-head\">✓ Advantages for Customers</div>\n<div class=\"pro-item\"><strong>Price comparison:</strong> Customers can easily compare prices across multiple sites, getting the best deal and saving money.</div>\n<div class=\"pro-item\"><strong>Seven-day availability:</strong> Customers can buy at any time convenient to them — not restricted to shop opening hours.</div>\n<div class=\"pro-item\"><strong>Wide range of products:</strong> The internet provides worldwide access, giving customers far greater choice than any single physical store could offer.</div>\n</div>\n<div>\n<div class=\"col-head\">✗ Disadvantages for Customers</div>\n<div class=\"con-item\"><strong>Lack of personal contact:</strong> No person to talk to directly, which may deter some customers — especially for complex or expensive purchases.</div>\n<div class=\"con-item\"><strong>Security risk:</strong> Customers worry about credit card and personal data being stolen, even with encryption available.</div>\n<div class=\"con-item\"><strong>Methods of payment:</strong> Customers who prefer cash cannot use e-commerce, as payment is geared towards credit/debit cards.</div>\n<div class=\"con-item\"><strong>Technology barriers:</strong> Some customers (especially older groups) lack internet access or confidence with technology.</div>\n<div class=\"con-item\"><strong>Only images seen:</strong> Cannot touch, feel, or try products before buying. This is less of a problem for familiar products (e.g. a known DVD) but significant for clothing or furniture.</div>\n</div>\n</div>", "question": "Which is listed as a disadvantage of e-commerce FOR CUSTOMERS?", "options": ["They cannot touch, feel, or try products before buying", "Businesses must maintain secure websites to protect customer data", "Businesses face worldwide competition from other online sellers", "Businesses must constantly update their technology to stay competitive"]}'::jsonb, '{"answer": 0, "explain": "''Only images seen'' — being unable to touch, feel, or try products — is listed as a customer disadvantage; the other options are business-side disadvantages."}'::jsonb),
('4-3-sales-process-customer-service:learn:261483d2', '4-3-sales-process-customer-service', '4.3 The Sales Process', 'learn', 'mcq', 1, '{"readingTitle": "Face to Face Selling & Telesales", "reading": "<p><strong>Face to face selling</strong> is typically done in a shop, bank, or travel agent. Key features:</p>\n<ul>\n<li>Direct interaction allows advice, demonstrations, questions, and answers</li>\n<li>Customers can see and handle products before buying</li>\n<li>Builds trust and personal relationships, encouraging return visits</li>\n<li>However, shops are <strong>expensive to operate</strong> — staff wages, rent, local taxes, cleaning and maintenance all apply</li>\n<li>Poor weather or inconvenience may push customers to shop online instead</li>\n</ul>\n<p><strong>Telesales</strong> bridges e-commerce and face to face. Key features:</p>\n<ul>\n<li>Useful for customers not comfortable with online shopping but happy to talk by phone</li>\n<li>Allows the customer to negotiate — e.g. renewing a mobile phone contract by phone lets them bargain for a better deal</li>\n<li>Larger businesses have dedicated telesales departments; smaller businesses may lack staff</li>\n<li><strong>Cold calling</strong> — unsolicited calls at inconvenient times — is seen as a nuisance by many customers</li>\n</ul>\n<div class=\"two-col\">\n<div>\n<div class=\"col-head\">✓ Best for Face to Face</div>\n<div class=\"pro-item\">High-value or complex products (e.g. cars, wedding dresses, electronics)</div>\n<div class=\"pro-item\">When service and advice are central to the buying decision</div>\n<div class=\"pro-item\">When customers want to touch or try the product before buying</div>\n</div>\n<div>\n<div class=\"col-head\">✓ Best for Telesales</div>\n<div class=\"con-item\">Renewing subscriptions or contracts (e.g. insurance, phone, utilities)</div>\n<div class=\"con-item\">Reaching customers who are not tech-savvy</div>\n<div class=\"con-item\">When customers want to negotiate terms or receive personalised guidance by phone</div>\n</div>\n</div>", "question": "Which selling method is most useful for a customer who wants to negotiate a better deal, e.g. renewing a mobile phone contract?", "options": ["Telesales", "Face to face selling", "E-commerce", "Click and collect"]}'::jsonb, '{"answer": 0, "explain": "The card states telesales allows the customer to negotiate — e.g. renewing a mobile phone contract by phone lets them bargain for a better deal."}'::jsonb),
('4-3-sales-process-customer-service:learn:208ae89a', '4-3-sales-process-customer-service', '4.3 The Sales Process', 'learn', 'mcq', 1, '{"readingTitle": "The Importance of Customer Service & After-Sales Service", "reading": "<p><strong>Customer service</strong> is vital to maintaining and increasing sales. A business must retain existing customers and attract new ones — losing customers to competitors is extremely costly.</p>\n<p>Good customer service is especially important where the product requires a high level of service — compare buying a book online (low service needed) with buying a wedding dress (high service, face-to-face essential).</p>\n<p><strong>After-sales service</strong> is what happens when things go wrong after a purchase. It might include:</p>\n<ul>\n<li>Offering refunds or exchanges (even where not legally required)</li>\n<li>Organising speedy repairs</li>\n<li>Keeping the customer informed about a problem being resolved</li>\n</ul>\n<p>The goal is to leave the customer satisfied, so they return and spend more in the future. Competitors are always ready to take customers from any business seen to be falling short on service.</p>\n<div class=\"two-col\">\n<div>\n<div class=\"col-head\">✓ Why After-Sales Service Matters</div>\n<div class=\"pro-item\">Ensures customers are satisfied after purchase, encouraging repeat business and loyalty.</div>\n<div class=\"pro-item\">Builds trust — customers who experience good problem resolution are more likely to return.</div>\n<div class=\"pro-item\">Positive word-of-mouth — satisfied customers recommend the business, attracting new customers at no extra marketing cost.</div>\n</div>\n<div>\n<div class=\"col-head\">✗ Risks of Poor After-Sales Service</div>\n<div class=\"con-item\">Customers switch to competitors after a bad post-purchase experience.</div>\n<div class=\"con-item\">Negative online reviews can rapidly damage brand reputation in the e-commerce age.</div>\n<div class=\"con-item\">Lost sales and reduced market share in the long run.</div>\n</div>\n</div>", "question": "Which purchase is used as the example of a product needing HIGH customer service, where face-to-face is essential?", "options": ["A wedding dress", "A book", "A DVD", "A phone contract renewal"]}'::jsonb, '{"answer": 0, "explain": "The card contrasts buying a book online (low service needed) with buying a wedding dress (high service, face-to-face essential)."}'::jsonb),
('4-3-sales-process-customer-service:learn:c295d646', '4-3-sales-process-customer-service', '4.3 The Sales Process', 'learn', 'mcq', 1, '{"readingTitle": "Product Knowledge & Customer Engagement", "reading": "<p><strong>Product knowledge</strong> is the detailed understanding staff have about what they sell. Its importance varies by business type:</p>\n<ul>\n<li>In a <strong>garden centre</strong>, staff need to advise on plants for specific conditions.</li>\n<li>In an <strong>electronics store</strong>, staff need to explain the latest TV or laptop technology to less-informed customers.</li>\n<li>In a <strong>newsagent</strong>, product knowledge is relatively less critical.</li>\n</ul>\n<p>Training costs time and money, but better product knowledge &rarr; better customer service &rarr; more sales &rarr; profits cover the cost of training.</p>\n<p><strong>Customer engagement</strong> is the contact between a customer and the business. Good engagement means:</p>\n<ul>\n<li>Well-trained, polite, knowledgeable staff in face-to-face settings</li>\n<li>A friendly, helpful voice in telesales</li>\n<li>Carefully worded emails and texts in e-commerce (replicating the feeling of face-to-face engagement)</li>\n</ul>\n<p>⚠️ There is a fine line between being helpful and being too \"pushy.\" Car salespeople have a reputation for over-engagement — too much information or pressure can drive customers away.</p>\n<div class=\"case-study-box\">\n<h4>Case Study: Amazon vs John Lewis</h4>\n<p>Amazon competes on <strong>price, choice, and speed of delivery</strong> — using Prime''s next-day and same-day delivery to stay ahead. John Lewis, by contrast, focuses on <strong>product knowledge and face-to-face customer engagement</strong>, especially important for complex electronics purchases where customers need explanation. Both approaches show that excellent customer service can take very different forms depending on the business model.</p>\n</div>", "question": "In which type of business does the guide say product knowledge is ''relatively less critical''?", "options": ["A newsagent", "A garden centre", "An electronics store", "A car dealership"]}'::jsonb, '{"answer": 0, "explain": "The guide states that in a newsagent, product knowledge is relatively less critical, unlike a garden centre or electronics store."}'::jsonb),
('4-3-sales-process-customer-service:learn:0c3b3528', '4-3-sales-process-customer-service', '4.3 The Sales Process', 'learn', 'mcq', 1, '{"readingTitle": "Real-World Application: Amazon & E-commerce Growth", "reading": "<div class=\"case-study-box\">\n<h4>Case Study: Amazon</h4>\n<p>Amazon was started by Jeff Bezos in 1994, initially selling books online. It later expanded into electronics, video games, and through Amazon Marketplace, an enormous range of products. It is now one of the world''s leading e-commerce businesses.</p>\n<p>Amazon has always responded to competitors by focusing on speed and enhanced service. In 2007 it launched its <strong>Prime service</strong> in the UK, promising next-day delivery. When competitors matched this, Amazon added \"extras\" — free music and video streaming, same-day food delivery through Morrisons, and exclusive \"Prime Day\" deals for subscribers.</p>\n<p>Prime is a subscription service, and consumers are willing to pay for this enhanced level of service. Amazon places great emphasis on <strong>pricing, choice, and speed of delivery</strong> rather than face-to-face customer engagement.</p>\n</div>\n<p><strong>Key takeaways for the exam:</strong></p>\n<ul>\n<li>Amazon is an e-commerce business because it brings buyers and sellers together digitally, with physical delivery following the online sale</li>\n<li>It competes through speed and choice rather than in-person customer engagement</li>\n<li>Its success is closely tied to the logistics industry (warehouses, delivery networks)</li>\n<li>The coronavirus pandemic of 2020–21 accelerated e-commerce growth, forcing many traditional retailers to adapt or close (e.g. Debenhams and Top Shop left the high street)</li>\n</ul>", "question": "In what year did Amazon launch its Prime service in the UK?", "options": ["2007", "1994", "2020", "2015"]}'::jsonb, '{"answer": 0, "explain": "The case study states ''In 2007 it launched its Prime service in the UK, promising next-day delivery.''"}'::jsonb),
('4-3-sales-process-customer-service:misc:477ec19f', '4-3-sales-process-customer-service', '4.3 The Sales Process', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Having a website means a business is doing e-commerce.</p><p><strong>✅ The correct idea:</strong> E-commerce means the business actually SELLS products online — not just advertises them. A business with only a promotional website that does not take online orders is NOT an e-commerce business.</p>", "question": "A business has a website that only advertises its products, with no way to buy online. Is this e-commerce?", "options": ["No – e-commerce requires actually selling online, not advertising", "Yes – any business website automatically counts as e-commerce", "Only if it''s a well-known brand with a large customer base", "Yes, as long as the website clearly lists prices and products"]}'::jsonb, '{"answer": 0, "explain": "E-commerce means the business actually sells online — a promotional-only website with no orders taken is not e-commerce."}'::jsonb),
('4-3-sales-process-customer-service:misc:97b4848c', '4-3-sales-process-customer-service', '4.3 The Sales Process', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> E-commerce is only suitable for large businesses like Amazon.</p><p><strong>✅ The correct idea:</strong> E-commerce is accessible to businesses of all sizes. A small business can set up a website for relatively little cost and reach a worldwide market, competing with larger firms in ways that were not possible before the internet.</p>", "question": "Which statement about e-commerce and business size is correct?", "options": ["Small businesses can use e-commerce to reach a worldwide market", "E-commerce is only suitable for large businesses like Amazon", "Only businesses with physical stores can succeed online", "E-commerce requires a large marketing budget to work at all"]}'::jsonb, '{"answer": 0, "explain": "E-commerce is accessible to businesses of all sizes — a small business can set up a website cheaply and reach a worldwide market."}'::jsonb),
('4-3-sales-process-customer-service:misc:03f6c93a', '4-3-sales-process-customer-service', '4.3 The Sales Process', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Customer service only means being polite to customers in a shop.</p><p><strong>✅ The correct idea:</strong> Customer service covers the FULL customer journey: before, during, AND after the sale. After-sales service (handling returns, repairs, complaints) is a critical and separately examinable component of good customer service.</p>", "question": "What does ''customer service'' actually cover, according to the guide?", "options": ["The full journey — before, during, and after the sale", "Only being polite to customers face-to-face in a shop", "Only handling complaints and returns after the sale is made", "Only advertising and promotion before the sale is made"]}'::jsonb, '{"answer": 0, "explain": "Customer service covers the full customer journey, including after-sales service, not just politeness in a shop."}'::jsonb),
('4-3-sales-process-customer-service:misc:6644e168', '4-3-sales-process-customer-service', '4.3 The Sales Process', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> E-commerce always reduces costs for a business.</p><p><strong>✅ The correct idea:</strong> While e-commerce can lower operating costs (no shop rent), it also creates NEW costs: website security, delivery logistics, returns handling, and keeping up with technology. The net financial effect depends on the specific business.</p>", "question": "Does e-commerce always reduce a business''s costs?", "options": ["No – it lowers some costs but adds new ones like security and logistics", "Yes – it always reduces costs because there is no shop rent to pay", "No – e-commerce always increases a business''s total operating costs", "Yes – because online businesses no longer need to employ any staff"]}'::jsonb, '{"answer": 0, "explain": "E-commerce can lower operating costs but also creates new costs such as website security, delivery logistics, and returns handling."}'::jsonb),
('4-3-sales-process-customer-service:misc:a14acc70', '4-3-sales-process-customer-service', '4.3 The Sales Process', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> A disadvantage of e-commerce to the customer is that it costs the business more money.</p><p><strong>✅ The correct idea:</strong> When a question asks for a disadvantage to the CUSTOMER, you must write about how the customer is negatively affected — not how the business is affected. Mixing up perspectives is one of the most common ways students lose marks.</p>", "question": "If a question asks for a disadvantage of e-commerce TO THE CUSTOMER, what must the answer focus on?", "options": ["How the customer is negatively affected", "How the business''s costs increase", "How the business loses market share", "How delivery companies are affected"]}'::jsonb, '{"answer": 0, "explain": "Mixing up perspectives is a common error — an answer about a ''disadvantage to the customer'' must focus on the customer, not the business."}'::jsonb),
('4-3-sales-process-customer-service:misc:cac16845', '4-3-sales-process-customer-service', '4.3 The Sales Process', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Good customer engagement means being as helpful and informative as possible at all times.</p><p><strong>✅ The correct idea:</strong> There is a fine line between being helpful and being ''pushy.'' Too much information or pressure can drive customers away. Good engagement means reading the customer''s needs and responding appropriately — not overwhelming them.</p>", "question": "According to the guide, what is the risk of ''too much'' customer engagement?", "options": ["It can feel pushy and drive customers away", "It always increases sales no matter how it''s done", "It has no downsides at all for the business", "It only affects online customers, not face-to-face ones"]}'::jsonb, '{"answer": 0, "explain": "There is a fine line between being helpful and being pushy — too much information or pressure can drive customers away."}'::jsonb),
('4-3-sales-process-customer-service:misc:ab9d2b71', '4-3-sales-process-customer-service', '4.3 The Sales Process', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Product knowledge is only important for face-to-face selling.</p><p><strong>✅ The correct idea:</strong> Product knowledge is also important in telesales (staff must advise customers over the phone) and e-commerce (website descriptions, FAQs, and live chat all require accurate, detailed product information).</p>", "question": "Is product knowledge only important for face-to-face selling?", "options": ["No – it also matters in telesales and in e-commerce websites", "Yes – it is completely irrelevant to telesales and e-commerce", "No – it only matters for e-commerce, not telesales", "Yes – only face-to-face shop staff need product knowledge"]}'::jsonb, '{"answer": 0, "explain": "Product knowledge also matters in telesales (advising by phone) and e-commerce (accurate website descriptions and live chat)."}'::jsonb),
('4-3-sales-process-customer-service:misc:f4420db2', '4-3-sales-process-customer-service', '4.3 The Sales Process', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Click and collect is the same as home delivery.</p><p><strong>✅ The correct idea:</strong> Click and collect means the customer orders online but COLLECTS from a store — there is NO home delivery. It is specifically designed to solve the problem of customers not being home when a delivery arrives.</p>", "question": "What is the key difference between click and collect and home delivery?", "options": ["Click and collect means collecting from a store, not delivery", "They are exactly the same thing with no real difference", "Click and collect is always faster than home delivery", "Click and collect only works for food and grocery shopping"]}'::jsonb, '{"answer": 0, "explain": "Click and collect means ordering online but collecting from a store — there is no home delivery involved."}'::jsonb),
('4-3-sales-process-customer-service:misc:7e5424e1', '4-3-sales-process-customer-service', '4.3 The Sales Process', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> E-commerce and digital distribution mean the same thing.</p><p><strong>✅ The correct idea:</strong> E-commerce involves an online sale followed by PHYSICAL delivery. Digital distribution means the product itself is delivered digitally (e.g. a downloaded game or e-book) with no physical delivery required.</p>", "question": "What is the key difference between e-commerce and digital distribution?", "options": ["E-commerce involves physical delivery, unlike digital", "They mean exactly the same thing in every situation", "Digital distribution always involves a physical shop instead", "E-commerce never involves any kind of delivery at all"]}'::jsonb, '{"answer": 0, "explain": "E-commerce involves an online sale followed by physical delivery, while digital distribution delivers the product itself digitally, e.g. a downloaded game or e-book."}'::jsonb),
('4-3-sales-process-customer-service:misc:e5cdaa6c', '4-3-sales-process-customer-service', '4.3 The Sales Process', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Telesales is becoming irrelevant because of e-commerce.</p><p><strong>✅ The correct idea:</strong> Telesales remains important as a bridge between e-commerce and face-to-face selling, particularly for older customers, subscription renewals (insurance, utilities, phone contracts), and situations where customers want to negotiate directly.</p>", "question": "Is telesales becoming irrelevant because of e-commerce?", "options": ["No – it remains important as a bridge for older customers", "Yes – it has been entirely replaced by e-commerce websites", "No – it is now more popular than face-to-face selling", "Yes – no businesses run telesales departments anymore at all"]}'::jsonb, '{"answer": 0, "explain": "Telesales remains important, particularly for older customers, subscription renewals, and customers who want to negotiate directly."}'::jsonb),
('4-3-sales-process-customer-service:tips:b9e3dce1', '4-3-sales-process-customer-service', '4.3 The Sales Process', 'tips', 'mcq', 1, '{"readingTitle": "Identify / State — 1 mark — One Point. Full Stop. Move On.", "reading": "\n      <p>A 1-mark <strong>''State'' or ''Identify''</strong> question needs exactly one correct point. No explanation. No case study. No paragraphs.</p>\n      <p><strong>The Formula:</strong> One specific, correct point = 1 mark ✅</p>\n      <ul>\n        <li><strong>❌ Bad Answer (0 marks):</strong> <em>\"Promotion.\"</em> — This is a marketing concept, not a method of selling.</li>\n        <li><strong>✅ Good Answer (1 mark):</strong> <em>\"E-commerce / telesales / face to face selling.\"</em></li>\n      </ul>\n      <p><strong>⚠️ Examiner Warning:</strong> Many students lost marks by writing promotional methods (price skimming, advertising) when asked for a <em>method of selling</em>. Read the exact question wording before writing.</p>\n      <p><strong>🚫 Knowledge Dumping Alert:</strong> Do NOT write a definition when asked to ''identify''. Just name the thing.</p>\n    ", "question": "For a 1-mark ''State'' or ''Identify'' question, what should your answer contain?", "options": ["One specific point, no explanation needed", "A full paragraph with U, APP and AN chains", "A dictionary-style term definition", "Two safety points, one per mark"]}'::jsonb, '{"answer": 0, "explain": "The tip states a 1-mark identify/state question needs exactly one correct point — no explanation, no case study."}'::jsonb),
('4-3-sales-process-customer-service:tips:e10de8f1', '4-3-sales-process-customer-service', '4.3 The Sales Process', 'tips', 'mcq', 1, '{"readingTitle": "Explain — 2 marks — Point + Explain = 2 Marks", "reading": "\n      <p>For a 2-mark <strong>''Explain''</strong> question, you need a point AND an explanation of how it works. Two sentences — two marks.</p>\n      <p><strong>The Formula:</strong></p>\n      <ul>\n        <li><strong>Sentence 1 — State the point (K/U):</strong> Name the advantage, disadvantage, or concept.</li>\n        <li><strong>Sentence 2 — Explain it (U):</strong> Say WHY or HOW it works.</li>\n      </ul>\n      <p><strong>❌ Bad Answer (1 mark max):</strong><br/><em>\"E-commerce means the business can sell more.\"</em><br/>Too vague — doesn''t explain the mechanism.</p>\n      <p><strong>✅ Good Answer (2 marks):</strong><br/><em>\"A business using e-commerce has lower operating costs (1) because it does not need to pay expensive city-centre rents for a physical shop (1).\"</em></p>\n      <p><strong>⚠️ Examiner Warning:</strong> Some students answered from the customer''s perspective when asked about a business advantage. Re-read: who does the question say the advantage is FOR?</p>\n    ", "question": "What error did the guide flag as a common mistake on this 2-mark ''explain'' question about a business advantage?", "options": ["Answering from the customer''s view, not the firm''s", "Forgetting to name the business anywhere at all", "Writing far too much content for the marks given", "Using bullet points, not full written sentences"]}'::jsonb, '{"answer": 0, "explain": "The examiner warning notes some students answered from the customer''s perspective when the question asked about a business advantage."}'::jsonb),
('4-3-sales-process-customer-service:tips:589551e5', '4-3-sales-process-customer-service', '4.3 The Sales Process', 'tips', 'mcq', 1, '{"readingTitle": "Analyse — 3 marks — The Holy Trinity: U → APP → AN", "reading": "\n      <p>A 3-mark analyse question requires all three elements. You will score <strong>ZERO for analysis</strong> if you don''t apply your answer to the specific business in the case study.</p>\n      <p><strong>The 3-Step Formula:</strong></p>\n      <ul>\n        <li><strong>Step 1 — Understanding (U):</strong> State the theory or benefit clearly.</li>\n        <li><strong>Step 2 — Application (APP):</strong> Directly reference the case study business with specific text evidence.</li>\n        <li><strong>Step 3 — Analysis (AN):</strong> State the financial or operational IMPACT on the business.</li>\n      </ul>\n      <p><strong>Sentence Starters:</strong></p>\n      <ul>\n        <li><em>U: \"Good product knowledge means staff can advise customers on...\"</em></li>\n        <li><em>APP: \"In the case of [Business Name], the text states that...\"</em></li>\n        <li><em>AN: \"This will lead to more sales, meaning...\" / \"As a result, the business will...\"</em></li>\n      </ul>\n      <p><strong>❌ Bad Answer (1 mark only):</strong><br/><em>\"Product knowledge helps employees advise customers so they buy more.\"</em><br/>No application to the specific business = maximum 1 mark.</p>\n      <p><strong>✅ Good Answer (3 marks):</strong><br/><em>\"Call centre employees need to be able to advise customers on what is best to buy (U). AZ''s products are sold to qualified medical professionals, hospitals and governments (APP), so if employees cannot answer technical questions, sales and profits may fall (AN).\"</em></p>\n      <p><strong>🚫 Knowledge Dumping Alert:</strong> Do not write everything you know about the topic. Answer the specific question with reference to the specific business.</p>\n    ", "question": "In the U → APP → AN structure for a 3-mark analyse question, what does ''APP'' require?", "options": ["Direct reference to the case study business with evidence", "A general definition of the relevant business theory", "A clear judgement or final recommendation on the issue", "A concluding evaluation using the ''it depends'' rule"]}'::jsonb, '{"answer": 0, "explain": "Application (APP) means directly referencing the case study business with specific text evidence — without it, you score zero for analysis."}'::jsonb),
('4-3-sales-process-customer-service:tips:b3a214a0', '4-3-sales-process-customer-service', '4.3 The Sales Process', 'tips', 'mcq', 1, '{"readingTitle": "Analyse (Two impacts) — 6 marks — Two 3-Mark Chains. No Conclusion Needed.", "reading": "\n      <p>A 6-mark question is simply a <strong>3-mark question done twice</strong>. You must analyse TWO separate impacts, each with its own U → APP → AN chain.</p>\n      <p><strong>⚠️ Critical Warning:</strong> There are <strong>ZERO marks</strong> available for a conclusion or evaluation here. Do NOT write \"Overall, I think...\" — it wastes time and scores nothing.</p>\n      <p><strong>Structure:</strong></p>\n      <ul>\n        <li><strong>Impact 1 (3 marks):</strong> U → APP → AN</li>\n        <li><strong>Impact 2 (3 marks):</strong> U → APP → AN</li>\n      </ul>\n      <p><strong>Sentence Starters for each paragraph:</strong></p>\n      <ul>\n        <li><em>\"One advantage/disadvantage is that... (U)\"</em></li>\n        <li><em>\"In the case of [Business], the text tells us that... (APP)\"</em></li>\n        <li><em>\"This means that... resulting in... (AN)\"</em></li>\n      </ul>\n      <p><strong>⚠️ Examiner Warning (Primark question):</strong> Many students wrote from the CUSTOMER''S point of view when the question asked about Primark Ltd. If the question says \"to Primark Ltd,\" every point must show how PRIMARK is affected — not how customers feel about it.</p>\n    ", "question": "How many marks are available for a conclusion or evaluation in a 6-mark ''analyse two impacts'' question?", "options": ["Zero", "One", "Three", "Six"]}'::jsonb, '{"answer": 0, "explain": "The guide is explicit that there are zero marks for a conclusion in a 6-mark ''two impacts'' analyse question — writing ''Overall, I think...'' wastes time and scores nothing."}'::jsonb),
('4-3-sales-process-customer-service:tips:4ce429a4', '4-3-sales-process-customer-service', '4.3 The Sales Process', 'tips', 'mcq', 1, '{"readingTitle": "Recommend — 3 marks — Decision + Contextual Justification", "reading": "\n      <p>A 3-mark recommend question is NOT just a repeat of advantages and disadvantages. It needs a <strong>clear decision</strong> supported by a <strong>contextual justification</strong>.</p>\n      <p><strong>The Formula:</strong></p>\n      <ul>\n        <li><strong>1 mark — Judgement:</strong> Make a clear recommendation (should / should not).</li>\n        <li><strong>2 marks — Contextual justification:</strong> Use EVIDENCE from the case study text to support your decision. The evidence must be USED (not just repeated).</li>\n        <li><strong>OR 1 mark — Non-contextual justification:</strong> A reason without specific text reference.</li>\n      </ul>\n      <p><strong>❌ Bad Answer (1 mark only):</strong><br/><em>\"Primark should continue click and collect because it is good for customers.\"</em><br/>Wrong perspective, no context used.</p>\n      <p><strong>✅ Good Answer (3 marks):</strong><br/><em>\"Primark should continue (JUDGEMENT). If it stops, it may lose customers who have already changed their buying habits and got used to ordering online, as the text states buying habits have already changed (CONTEXT). This would reduce Primark''s revenue and market share. (+2 MARKS)\"</em></p>\n      <p><strong>⚠️ Examiner Comment:</strong> Less than a quarter of students got full marks on this type of question. Most could make a recommendation but could not justify it using the context — they repeated the text rather than using it to support their argument.</p>\n    ", "question": "What does a full 3-mark ''recommend'' answer require beyond a simple advantage/disadvantage list?", "options": ["A clear judgement supported by contextual justification", "Only a simple yes or no decision with no reasoning", "A list of three separate recommendations for the business", "An evaluation paragraph using the ''it depends'' rule"]}'::jsonb, '{"answer": 0, "explain": "A 3-mark recommend answer needs 1 mark for judgement and 2 marks for contextual justification, using case study evidence that is actually used, not just repeated."}'::jsonb),
('4-3-sales-process-customer-service:tips:2f84d3dd', '4-3-sales-process-customer-service', '4.3 The Sales Process', 'tips', 'mcq', 1, '{"readingTitle": "Evaluate — 9 marks — Four-Paragraph Structure for Full Marks", "reading": "\n      <p>A 9-mark evaluate question tests your ability to argue both sides and make a justified judgement. Structure your answer in <strong>four paragraphs</strong>:</p>\n      <ul>\n        <li><strong>Paragraph 1 — Knowledge & Understanding (K + U):</strong> Define key concepts relevant to the question (e.g. what customer service is, what growth means as a business objective).</li>\n        <li><strong>Paragraph 2 — First side with analysis (AN + APP):</strong> Argue FOR the importance of customer service, with a full chain of reasoning linked to the specific business.</li>\n        <li><strong>Paragraph 3 — Counterargument with analysis (AN + APP):</strong> Argue against or present a counter-view (e.g. other factors affecting growth such as price or competition from no-frills rivals).</li>\n        <li><strong>Paragraph 4 — Evaluation (EVAL — 3 marks):</strong> Write a justified conclusion using the \"It depends on...\" rule. Decision + Context + Impact/Reasoning.</li>\n      </ul>\n      <p><strong>Evaluation Sentence Starters:</strong></p>\n      <ul>\n        <li><em>\"Overall, good customer service is important to Virgin Atlantic achieving growth because...\"</em></li>\n        <li><em>\"However, this depends on whether Virgin Atlantic is targeting price-conscious customers or premium travellers...\"</em></li>\n        <li><em>\"In conclusion, I recommend... because... but this depends on...\"</em></li>\n      </ul>\n      <p><strong>⚠️ Evaluation Warning:</strong> A conclusion that only repeats what you already wrote scores ZERO for evaluation. The \"It depends on...\" must introduce a NEW condition or consideration not already covered.</p>\n      <p><strong>🚫 Knowledge Dumping Alert:</strong> Do NOT list every fact you know about customer service. Every sentence must be specifically linked to the business''s objective in the question.</p>\n    ", "question": "According to the guide, what makes a concluding ''it depends on...'' statement score zero for evaluation?", "options": ["Repeating earlier points instead of a new condition", "Placing it in paragraph four, not paragraph one", "Failing to mention the business by name", "Writing fewer than two full sentences"]}'::jsonb, '{"answer": 0, "explain": "The evaluation warning states a conclusion that only repeats what was already written scores zero — the ''it depends'' must introduce a new condition not already covered."}'::jsonb),
('4-3-sales-process-customer-service:tips:8d63ab7f', '4-3-sales-process-customer-service', '4.3 The Sales Process', 'tips', 'mcq', 1, '{"readingTitle": "Perspective Trap — All Questions — Business vs Customer: Never Mix These Up", "reading": "\n      <p>One of the most common ways students lose marks in 4.3 is answering from the <strong>wrong perspective</strong>.</p>\n      <p><strong>Always identify WHO the question is asking about before you write:</strong></p>\n      <ul>\n        <li>If the question says \"advantage to the BUSINESS\" — every point must show how the BUSINESS benefits.</li>\n        <li>If the question says \"disadvantage to the CUSTOMER\" — every point must show how the CUSTOMER is negatively affected.</li>\n      </ul>\n      <p><strong>Examples of the perspective trap:</strong></p>\n      <ul>\n        <li><strong>❌ Wrong (0 marks):</strong> Answering \"customers can''t touch the product\" when asked about a disadvantage to M&S of selling food via e-commerce. That is a customer disadvantage.</li>\n        <li><strong>✅ Right (1 mark):</strong> \"M&S may suffer reputational damage if its website crashes, leading to a loss of customers and reduced revenue.\" — This is a business disadvantage.</li>\n      </ul>\n      <p><strong>⚠️ Direct Examiner Quote:</strong> On the Primark question, many students wrote advantages and disadvantages from the customer''s point of view even when the question clearly asked about Primark Ltd. This was one of the main reasons students scored 0 marks on that question.</p>\n    ", "question": "On the Primark question referenced in the guide, what was the main reason many students scored 0 marks?", "options": ["They wrote points from the customer''s view, not Primark''s", "They forgot to mention click and collect at all", "They ran out of exam time before finishing the answer", "They used bullet points instead of full written paragraphs"]}'::jsonb, '{"answer": 0, "explain": "The direct examiner quote notes many students wrote from the customer''s point of view even though the question asked about Primark Ltd, causing them to score 0."}'::jsonb),
