('4-3-sales-process-customer-service:match:dfb92d35', '4-3-sales-process-customer-service', '4.3 The Sales Process', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “E-commerce”?", "options": ["The name given to an area of business that deals with customer enquiries.", "The contact between the business and customer.", "The bringing together of buying and selling electronically.", "Ordering online and collecting goods from store at a later time."]}'::jsonb, '{"answer": 2, "explain": "“E-commerce” means: The bringing together of buying and selling electronically."}'::jsonb),
('4-3-sales-process-customer-service:match:29bc740e', '4-3-sales-process-customer-service', '4.3 The Sales Process', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Customer service”?", "options": ["The name given to an area of business that deals with customer enquiries.", "The contact between the business and customer.", "Ordering online and collecting goods from store at a later time.", "Usually completed in a shop where there is direct contact between buyer and seller."]}'::jsonb, '{"answer": 0, "explain": "“Customer service” means: The name given to an area of business that deals with customer enquiries."}'::jsonb),
('4-3-sales-process-customer-service:match:824623fd', '4-3-sales-process-customer-service', '4.3 The Sales Process', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Customer engagement”?", "options": ["Ordering online and collecting goods from store at a later time.", "Usually completed in a shop where there is direct contact between buyer and seller.", "The contact between the business and customer.", "Sales completed over the telephone."]}'::jsonb, '{"answer": 2, "explain": "“Customer engagement” means: The contact between the business and customer."}'::jsonb),
('4-3-sales-process-customer-service:match:1e57b9f6', '4-3-sales-process-customer-service', '4.3 The Sales Process', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Click and collect”?", "options": ["Ordering online and collecting goods from store at a later time.", "Usually completed in a shop where there is direct contact between buyer and seller.", "Sales completed over the telephone.", "Advice and help given to a customer after they have bought a product or service."]}'::jsonb, '{"answer": 0, "explain": "“Click and collect” means: Ordering online and collecting goods from store at a later time."}'::jsonb),
('4-3-sales-process-customer-service:match:f61a3c15', '4-3-sales-process-customer-service', '4.3 The Sales Process', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Face to face selling”?", "options": ["Usually completed in a shop where there is direct contact between buyer and seller.", "Sales completed over the telephone.", "Advice and help given to a customer after they have bought a product or service.", "The detailed knowledge of a product or service that staff within a business use to help persuade a customer to buy."]}'::jsonb, '{"answer": 0, "explain": "“Face to face selling” means: Usually completed in a shop where there is direct contact between buyer and seller."}'::jsonb),
('4-3-sales-process-customer-service:match:8ec5977f', '4-3-sales-process-customer-service', '4.3 The Sales Process', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Telesales”?", "options": ["Advice and help given to a customer after they have bought a product or service.", "The detailed knowledge of a product or service that staff within a business use to help persuade a customer to buy.", "An advantage of e-commerce to customers — the ability to easily compare prices across multiple sellers to find the best deal.", "Sales completed over the telephone."]}'::jsonb, '{"answer": 3, "explain": "“Telesales” means: Sales completed over the telephone."}'::jsonb),
('4-3-sales-process-customer-service:match:c1a931d3', '4-3-sales-process-customer-service', '4.3 The Sales Process', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “After-sales service”?", "options": ["The detailed knowledge of a product or service that staff within a business use to help persuade a customer to buy.", "Advice and help given to a customer after they have bought a product or service.", "An advantage of e-commerce to customers — the ability to easily compare prices across multiple sellers to find the best deal.", "Unsolicited telesales calls made to potential customers at home, often at inconvenient times, widely viewed as a nuisance."]}'::jsonb, '{"answer": 1, "explain": "“After-sales service” means: Advice and help given to a customer after they have bought a product or service."}'::jsonb),
('4-3-sales-process-customer-service:match:0ce1744b', '4-3-sales-process-customer-service', '4.3 The Sales Process', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Product knowledge”?", "options": ["An advantage of e-commerce to customers — the ability to easily compare prices across multiple sellers to find the best deal.", "Unsolicited telesales calls made to potential customers at home, often at inconvenient times, widely viewed as a nuisance.", "The detailed knowledge of a product or service that staff within a business use to help persuade a customer to buy.", "The industry responsible for the movement and delivery of goods to customers; closely linked to the success of e-commerce."]}'::jsonb, '{"answer": 2, "explain": "“Product knowledge” means: The detailed knowledge of a product or service that staff within a business use to help persuade a customer to buy."}'::jsonb),
('4-3-sales-process-customer-service:match:09c9f47d', '4-3-sales-process-customer-service', '4.3 The Sales Process', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Price comparison”?", "options": ["Unsolicited telesales calls made to potential customers at home, often at inconvenient times, widely viewed as a nuisance.", "The industry responsible for the movement and delivery of goods to customers; closely linked to the success of e-commerce.", "A subscription service offering next-day and same-day delivery plus streaming benefits, used by Amazon to stay ahead of competitors.", "An advantage of e-commerce to customers — the ability to easily compare prices across multiple sellers to find the best deal."]}'::jsonb, '{"answer": 3, "explain": "“Price comparison” means: An advantage of e-commerce to customers — the ability to easily compare prices across multiple sellers to find the best deal."}'::jsonb),
('4-3-sales-process-customer-service:match:b46aef5c', '4-3-sales-process-customer-service', '4.3 The Sales Process', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Cold calling”?", "options": ["The industry responsible for the movement and delivery of goods to customers; closely linked to the success of e-commerce.", "Unsolicited telesales calls made to potential customers at home, often at inconvenient times, widely viewed as a nuisance.", "A subscription service offering next-day and same-day delivery plus streaming benefits, used by Amazon to stay ahead of competitors.", "The bringing together of buying and selling electronically."]}'::jsonb, '{"answer": 1, "explain": "“Cold calling” means: Unsolicited telesales calls made to potential customers at home, often at inconvenient times, widely viewed as a nuisance."}'::jsonb),
('4-3-sales-process-customer-service:match:bbe41fe0', '4-3-sales-process-customer-service', '4.3 The Sales Process', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Logistics”?", "options": ["A subscription service offering next-day and same-day delivery plus streaming benefits, used by Amazon to stay ahead of competitors.", "The bringing together of buying and selling electronically.", "The industry responsible for the movement and delivery of goods to customers; closely linked to the success of e-commerce.", "The name given to an area of business that deals with customer enquiries."]}'::jsonb, '{"answer": 2, "explain": "“Logistics” means: The industry responsible for the movement and delivery of goods to customers; closely linked to the success of e-commerce."}'::jsonb),
('4-3-sales-process-customer-service:match:9787c244', '4-3-sales-process-customer-service', '4.3 The Sales Process', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Amazon Prime”?", "options": ["A subscription service offering next-day and same-day delivery plus streaming benefits, used by Amazon to stay ahead of competitors.", "The bringing together of buying and selling electronically.", "The name given to an area of business that deals with customer enquiries.", "The contact between the business and customer."]}'::jsonb, '{"answer": 0, "explain": "“Amazon Prime” means: A subscription service offering next-day and same-day delivery plus streaming benefits, used by Amazon to stay ahead of competitors."}'::jsonb),
('4-4-consumer-law:exam:cb64d624', '4-4-consumer-law', '4.4 Consumer Law', 'exam', 'mcq', 1, '{"num": "Q2", "question": "A company makes wooden jigsaw puzzles. By law, the company must: [1 mark]", "options": ["Buy its wood from local suppliers", "Deliver the jigsaw puzzles in electric vans", "Replace any pieces that customers lose", "Use paint that is non-toxic and safe"], "hint": "Consumer law is about the safety and quality of the product itself — not about where raw materials come from or how the product is delivered.", "starter": "The correct answer is D, because consumer law requires goods to be..."}'::jsonb, '{"answer": 3, "markScheme": "<div class=\"marks-section\"><h5>Answer: D — Use paint that is non-toxic and safe (1 mark)</h5></div><div class=\"marks-section\"><h5>Why the Other Options Are Wrong</h5><ul><li><strong>A — Buy its wood from local suppliers:</strong> Consumer law does not specify where raw materials must be sourced from. Using local suppliers may be an ethical or logistical choice, but it has no legal requirement under the Consumer Rights Act 2015.</li><li><strong>B — Deliver in electric vans:</strong> The method of delivery is not regulated by consumer law. This may relate to environmental responsibility, but the Consumer Rights Act does not require a specific delivery method.</li><li><strong>C — Replace pieces customers lose:</strong> The Consumer Rights Act does not require businesses to replace items lost through customer negligence. Consumer rights apply to faults present at the time of purchase — not losses caused by the customer.</li><li><strong>D — Use non-toxic and safe paint (CORRECT):</strong> Consumer law requires goods to be of satisfactory quality and safe to use. Using non-toxic paint ensures the product is safe for the consumer — especially critical for a product that children might handle.</li></ul></div>", "modelAnswer": ""}'::jsonb),
('4-4-consumer-law:exam:4e560506', '4-4-consumer-law', '4.4 Consumer Law', 'exam', 'mcq', 1, '{"num": "Q3", "question": "A customer has bought a laptop from a computer shop. By law, the computer shop must: [1 mark]", "options": ["Match the price charged by a local competitor", "Offer to upgrade the laptop for no extra charge", "Provide virus protection to keep the customer''s files safe", "Supply a laptop of satisfactory quality"], "hint": "Think about the three key requirements of the Consumer Rights Act 2015. Which one applies directly here?", "starter": "The correct answer is D, because the Consumer Rights Act requires goods to be..."}'::jsonb, '{"answer": 3, "markScheme": "<div class=\"marks-section\"><h5>Answer: D — Supply a laptop of satisfactory quality (1 mark — AO2)</h5></div><div class=\"marks-section\"><h5>Why the Other Options Are Wrong</h5><ul><li><strong>A — Match the price of a local competitor:</strong> Price matching is not a legal requirement. Consumer law does not regulate pricing — businesses are free to charge what they choose.</li><li><strong>B — Offer a free upgrade:</strong> Upgrades are a customer service gesture, not a legal obligation. The Consumer Rights Act does not require businesses to offer product upgrades at any point.</li><li><strong>C — Provide virus protection:</strong> Installing software or providing cybersecurity is not a requirement under consumer law. It may be offered as an extra service, but the Consumer Rights Act 2015 does not mandate it.</li><li><strong>D — Supply a laptop of satisfactory quality (CORRECT):</strong> The Consumer Rights Act 2015 requires all goods to be of satisfactory quality — free from defects and appropriate for the price paid. This is the core legal obligation of any seller.</li></ul></div>", "modelAnswer": ""}'::jsonb),
('4-4-consumer-law:exam:5ce53b29', '4-4-consumer-law', '4.4 Consumer Law', 'exam', 'mcq', 1, '{"num": "Q5", "question": "A customer has ordered an electric shower from a plumbing firm. By law, the plumbing firm must: [1 mark]", "options": ["Charge a lower price than other plumbers", "Fit the shower without turning the water off", "Supply a shower that meets current safety standards", "Use an environmentally friendly supplier"], "hint": "Consumer law focuses on the safety and quality of goods supplied — not on pricing or the environmental sourcing of materials.", "starter": "The correct answer is C, because consumer law requires goods to be..."}'::jsonb, '{"answer": 2, "markScheme": "<div class=\"marks-section\"><h5>Answer: C — Supply a shower that meets current safety standards (1 mark)</h5></div><div class=\"marks-section\"><h5>Why the Other Options Are Wrong</h5><ul><li><strong>A — Charge a lower price than other plumbers:</strong> Pricing is not regulated by consumer law. There is no legal obligation to undercut competitors — businesses are free to set their own prices.</li><li><strong>B — Fit the shower without turning the water off:</strong> This is not a requirement of consumer law, and would in fact be dangerous and unsafe — directly contradicting the spirit of consumer protection legislation.</li><li><strong>C — Supply a shower that meets current safety standards (CORRECT):</strong> Consumer law requires goods and services to be of satisfactory quality, which includes meeting current safety standards. A shower must be safe, functional, and fit for the purpose of providing hot water.</li><li><strong>D — Use an environmentally friendly supplier:</strong> Environmental sourcing is an ethical consideration, not a legal consumer law requirement. Consumer law is about the rights of the buyer — not the environmental practices of the supply chain.</li></ul></div>", "modelAnswer": ""}'::jsonb),
('4-4-consumer-law:exam:e0ef9818', '4-4-consumer-law', '4.4 Consumer Law', 'exam', 'mcq', 1, '{"num": "Q7", "question": "Consumer law requires shops to sell goods that are: [1 mark]", "options": ["Cheap", "High quality", "Safe", "Unique"], "hint": "Consumer law doesn''t require goods to be the best or the cheapest — think about the word used in the law itself for the quality requirement.", "starter": "The correct answer is C, because consumer law requires goods to be..."}'::jsonb, '{"answer": 2, "markScheme": "<div class=\"marks-section\"><h5>Answer: C — Safe (1 mark — AO1a)</h5></div><div class=\"marks-section\"><h5>Why the Other Options Are Wrong</h5><ul><li><strong>A — Cheap:</strong> Consumer law does not require goods to be cheap. There is no price regulation in the Consumer Rights Act 2015 — businesses are free to charge market rates.</li><li><strong>B — High quality:</strong> This is the most common wrong answer. The law requires ''satisfactory quality'' — a standard that reflects the price paid — NOT the highest possible quality. Luxury goods must be high quality; budget goods only need to meet a lower, price-appropriate standard.</li><li><strong>C — Safe (CORRECT):</strong> Consumer law requires goods to be safe and of satisfactory quality. Safety is a core requirement — goods must not cause harm to the consumer when used as intended.</li><li><strong>D — Unique:</strong> Consumer law places no requirement on uniqueness or exclusivity. There is no legal reason a business cannot sell standard, mass-produced goods.</li></ul></div>", "modelAnswer": ""}'::jsonb),
('4-4-consumer-law:exam:1422879a', '4-4-consumer-law', '4.4 Consumer Law', 'exam', 'mcq', 1, '{"num": "Q8", "question": "Consumer law requires shops to sell goods which are: [1 mark]", "options": ["Environmentally friendly", "Of satisfactory quality", "Reasonably priced", "Unique"], "hint": "Think about the exact wording used in the Consumer Rights Act 2015 for the quality requirement.", "starter": "The correct answer is B, because the Consumer Rights Act 2015 specifically states that goods must be..."}'::jsonb, '{"answer": 1, "markScheme": "<div class=\"marks-section\"><h5>Answer: B — Of satisfactory quality (1 mark — AO1a)</h5></div><div class=\"marks-section\"><h5>Why the Other Options Are Wrong</h5><ul><li><strong>A — Environmentally friendly:</strong> Environmental responsibility is an ethical choice, not a legal consumer law requirement. The Consumer Rights Act 2015 makes no mention of environmental standards.</li><li><strong>B — Of satisfactory quality (CORRECT):</strong> The Consumer Rights Act 2015 specifically requires goods to be of satisfactory quality — not defective or damaged when sold, and appropriate for the price paid. This is one of the three core legal requirements.</li><li><strong>C — Reasonably priced:</strong> Consumer law does not regulate pricing. Businesses are free to charge market rates. ''Reasonably priced'' is not a requirement found anywhere in the Consumer Rights Act 2015.</li><li><strong>D — Unique:</strong> Consumer law places no requirement on uniqueness. Mass-produced, standard goods are perfectly legal to sell and fully covered by consumer law.</li></ul></div>", "modelAnswer": ""}'::jsonb),
('4-4-consumer-law:mcq:08014156', '4-4-consumer-law', '4.4 Consumer Law', 'mcq', 'mcq', 1, '{"question": "When buying any goods or services, customers are entitled to expect:", "options": ["The goods to be of the best standard possible", "The goods to be of satisfactory quality", "The goods to be guaranteed for three years", "The goods to be the same price as competitors"]}'::jsonb, '{"answer": 1, "explain": "Correct answer: B — Of satisfactory quality. The Consumer Rights Act 2015 requires goods to be of ''satisfactory quality'' reflecting their price — not the absolute best quality possible. There is no legal requirement for a guarantee period, price matching, or best-in-class standards."}'::jsonb),
('4-4-consumer-law:mcq:0a905c12', '4-4-consumer-law', '4.4 Consumer Law', 'mcq', 'mcq', 1, '{"question": "A business must sell goods that:", "options": ["Do what they are meant to do", "Perform as well as competitor goods", "Are made to last for years", "Are as cheap as possible"]}'::jsonb, '{"answer": 0, "explain": "Correct answer: A — Do what they are meant to do. This is the ''fit for purpose'' requirement of the Consumer Rights Act 2015. Businesses have no legal obligation to match competitors'' performance, guarantee longevity, or price goods cheaply."}'::jsonb),
('4-4-consumer-law:mcq:f2078ada', '4-4-consumer-law', '4.4 Consumer Law', 'mcq', 'mcq', 1, '{"question": "A way in which a business can be affected by consumer law is:", "options": ["Having compensation claims because goods are of high quality", "Losing reputation due to defective goods", "Having to sack staff who are always late for work", "Profits being reduced by paying higher wages"]}'::jsonb, '{"answer": 1, "explain": "Correct answer: B — Losing reputation due to defective goods. Producing defective goods leads to customer complaints, negative social media posts, and a damaged reputation. Sacking staff and wage levels are employment law issues — not consumer law."}'::jsonb),
('4-4-consumer-law:mcq:80a9cb40', '4-4-consumer-law', '4.4 Consumer Law', 'mcq', 'mcq', 1, '{"question": "The loss of a good reputation may mean a business:", "options": ["Can spend less money on advertising its products", "Has to increase production to meet demand", "Can afford to give staff a pay rise", "May have difficulty in recruiting staff"]}'::jsonb, '{"answer": 3, "explain": "Correct answer: D — May have difficulty recruiting staff. A poor reputation makes it harder to attract talented workers who want to be associated with respected companies. A damaged reputation would not reduce advertising needs, increase demand, or free up funds for pay rises."}'::jsonb),
('4-4-consumer-law:mcq:8e110c30', '4-4-consumer-law', '4.4 Consumer Law', 'mcq', 'mcq', 1, '{"question": "A company makes wooden jigsaw puzzles. By law, the company must:", "options": ["Buy its wood from local suppliers", "Deliver the jigsaw puzzles in electric vans", "Replace any pieces that customers lose", "Use paint that is non-toxic and safe"]}'::jsonb, '{"answer": 3, "explain": "Correct answer: D — Use paint that is non-toxic and safe. Consumer law requires goods to be safe and of satisfactory quality. Using non-toxic paint ensures the product is safe to handle. There is no legal requirement to use local suppliers, deliver by electric van, or replace pieces lost through customer negligence."}'::jsonb),
('4-4-consumer-law:mcq:4eaf64d2', '4-4-consumer-law', '4.4 Consumer Law', 'mcq', 'mcq', 1, '{"question": "A customer has bought a laptop from a computer shop. By law, the computer shop must:", "options": ["Match the price charged by a local competitor", "Offer to upgrade the laptop for no extra charge", "Provide virus protection to keep the customer''s files safe", "Supply a laptop of satisfactory quality"]}'::jsonb, '{"answer": 3, "explain": "Correct answer: D — Supply a laptop of satisfactory quality. The Consumer Rights Act 2015 requires goods to be of satisfactory quality — free from defects. Price matching, upgrades, and virus protection may be offered as good customer service, but none are required by law."}'::jsonb),
('4-4-consumer-law:mcq:ecbacf95', '4-4-consumer-law', '4.4 Consumer Law', 'mcq', 'mcq', 1, '{"question": "A customer has ordered an electric shower from a plumbing firm. By law, the plumbing firm must:", "options": ["Charge a lower price than other plumbers", "Fit the shower without turning the water off", "Supply a shower that meets current safety standards", "Use an environmentally friendly supplier"]}'::jsonb, '{"answer": 2, "explain": "Correct answer: C — Supply a shower that meets current safety standards. Consumer law requires goods and services to be safe and of satisfactory quality. There is no legal requirement to undercut competitors'' prices, use a specific installation method, or source from eco-friendly suppliers."}'::jsonb),
('4-4-consumer-law:mcq:8b7f2ba4', '4-4-consumer-law', '4.4 Consumer Law', 'mcq', 'mcq', 1, '{"question": "Consumer law requires shops to sell goods that are:", "options": ["Cheap", "High quality", "Safe", "Unique"]}'::jsonb, '{"answer": 2, "explain": "Correct answer: C — Safe. Consumer law requires goods to be safe (of satisfactory quality and fit for purpose). ''High quality'' is a very common distractor — the law only requires ''satisfactory'' quality, not the highest quality. Price and uniqueness are not legal requirements."}'::jsonb)
